function solve(grid: number[][], k: number): number {
    const m = grid.length;
    const n = grid[0].length;
    const dist = Array(m).fill(0).map(() => Array(n).fill(Infinity));
    dist[0][0] = 0;

    const dirs = [[0, 1], [1, 0]]; // right, down

    // Dijkstra's algorithm with priority queue
    const pq = new PriorityQueue<[number, number, number]>();
    pq.enqueue([0, 0, 0]); // [cost, row, col]

    while (!pq.isEmpty()) {
        const [cost, row, col] = pq.dequeue();

        if (row === m - 1 && col === n - 1) {
            return cost;
        }

        if (cost > dist[row][col]) continue;

        // Regular moves
        for (const [dr, dc] of dirs) {
            const newRow = row + dr;
            const newCol = col + dc;
            if (newRow >= 0 && newRow < m && newCol >= 0 && newCol < n) {
                const newCost = cost + grid[newRow][newCol];
                if (newCost < dist[newRow][newCol]) {
                    dist[newRow][newCol] = newCost;
                    pq.enqueue([newCost, newRow, newCol]);
                }
            }
        }

        // Teleportation
        for (let i = 0; i < m; i++) {
            for (let j = 0; j < n; j++) {
                if (grid[i][j] <= grid[row][col] && i !== row && j !== col) {
                    if (dist[i][j] > cost) {
                        dist[i][j] = cost;
                        pq.enqueue([cost, i, j]);
                    }
                }
            }
        }
    }

    return dist[m - 1][n - 1];
}

class PriorityQueue<T> {
    private heap: T[] = [];
    private comparator: (a: T, b: T) => number = (a, b) => {
        return a[0] - b[0];
    };

    enqueue(item: T): void {
        this.heap.push(item);
        this.heap.sort(this.comparator);
    }

    dequeue(): T {
        return this.heap.shift() as T;
    }

    isEmpty(): boolean {
        return this.heap.length === 0;
    }
}

